import { jest } from '@jest/globals';
import ToolRegistry from '../src/tools/ToolRegistry.js';

describe('ToolRegistry', () => {
  let registry;
  let mockFileSystemManager;
  let mockSearchEngine;
  let mockCommandExecutor;

  beforeEach(() => {
    mockFileSystemManager = {
      readFile: jest.fn(),
      writeFile: jest.fn()
    };

    mockSearchEngine = {
      search: jest.fn()
    };

    mockCommandExecutor = {
      execute: jest.fn()
    };

    registry = new ToolRegistry(
      mockFileSystemManager,
      mockSearchEngine,
      mockCommandExecutor
    );
  });

  describe('registerTool', () => {
    it('should register a tool with valid schema and handler', () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool',
        parameters: {
          type: 'object',
          properties: {
            param1: { type: 'string' }
          }
        }
      };

      registry.registerTool('test_tool', schema, handler);

      expect(registry.hasTool('test_tool')).toBe(true);
    });

    it('should throw error if tool name is not a string', () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool',
        parameters: { type: 'object' }
      };

      expect(() => {
        registry.registerTool(null, schema, handler);
      }).toThrow('Tool name must be a non-empty string');
    });

    it('should throw error if schema is missing', () => {
      const handler = jest.fn();

      expect(() => {
        registry.registerTool('test_tool', null, handler);
      }).toThrow('Tool schema must be an object');
    });

    it('should throw error if handler is not a function', () => {
      const schema = {
        description: 'Test tool',
        parameters: { type: 'object' }
      };

      expect(() => {
        registry.registerTool('test_tool', schema, 'not a function');
      }).toThrow('Tool handler must be a function');
    });

    it('should throw error if schema is missing description', () => {
      const handler = jest.fn();
      const schema = {
        parameters: { type: 'object' }
      };

      expect(() => {
        registry.registerTool('test_tool', schema, handler);
      }).toThrow('must have a description');
    });

    it('should throw error if schema is missing parameters', () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool'
      };

      expect(() => {
        registry.registerTool('test_tool', schema, handler);
      }).toThrow('must have parameters object');
    });
  });

  describe('getToolDefinitions', () => {
    it('should return empty array when no tools registered', () => {
      const definitions = registry.getToolDefinitions();
      expect(definitions).toEqual([]);
    });

    it('should return tool definitions in Mistral AI format', () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool',
        parameters: {
          type: 'object',
          properties: {
            param1: { type: 'string', description: 'A parameter' }
          },
          required: ['param1']
        }
      };

      registry.registerTool('test_tool', schema, handler);

      const definitions = registry.getToolDefinitions();

      expect(definitions).toHaveLength(1);
      expect(definitions[0]).toEqual({
        type: 'function',
        function: {
          name: 'test_tool',
          description: 'Test tool',
          parameters: {
            type: 'object',
            properties: {
              param1: { type: 'string', description: 'A parameter' }
            },
            required: ['param1']
          }
        }
      });
    });

    it('should return multiple tool definitions', () => {
      const handler1 = jest.fn();
      const handler2 = jest.fn();

      registry.registerTool('tool1', {
        description: 'First tool',
        parameters: { type: 'object' }
      }, handler1);

      registry.registerTool('tool2', {
        description: 'Second tool',
        parameters: { type: 'object' }
      }, handler2);

      const definitions = registry.getToolDefinitions();

      expect(definitions).toHaveLength(2);
      expect(definitions[0].function.name).toBe('tool1');
      expect(definitions[1].function.name).toBe('tool2');
    });
  });

  describe('executeTool', () => {
    it('should execute a registered tool successfully', async () => {
      const handler = jest.fn().mockResolvedValue('test result');
      const schema = {
        description: 'Test tool',
        parameters: {
          type: 'object',
          properties: {
            param1: { type: 'string' }
          },
          required: ['param1']
        }
      };

      registry.registerTool('test_tool', schema, handler);

      const result = await registry.executeTool('test_tool', { param1: 'value1' });

      expect(result.success).toBe(true);
      expect(result.result).toBe('test result');
      expect(handler).toHaveBeenCalledWith({ param1: 'value1' });
    });

    it('should throw error for non-existent tool', async () => {
      await expect(
        registry.executeTool('non_existent_tool', {})
      ).rejects.toThrow('Tool not found: non_existent_tool');
    });

    it('should return error result if handler throws', async () => {
      const handler = jest.fn().mockRejectedValue(new Error('Handler error'));
      const schema = {
        description: 'Test tool',
        parameters: {
          type: 'object',
          properties: {}
        }
      };

      registry.registerTool('test_tool', schema, handler);

      const result = await registry.executeTool('test_tool', {});

      expect(result.success).toBe(false);
      expect(result.error).toBe('Handler error');
    });

    it('should validate required parameters', async () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool',
        parameters: {
          type: 'object',
          properties: {
            param1: { type: 'string' }
          },
          required: ['param1']
        }
      };

      registry.registerTool('test_tool', schema, handler);

      const result = await registry.executeTool('test_tool', {});

      expect(result.success).toBe(false);
      expect(result.error).toContain('Missing required parameter');
    });

    it('should validate parameter types', async () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool',
        parameters: {
          type: 'object',
          properties: {
            param1: { type: 'string' }
          },
          required: ['param1']
        }
      };

      registry.registerTool('test_tool', schema, handler);

      const result = await registry.executeTool('test_tool', { param1: 123 });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid type');
    });

    it('should allow null and undefined values', async () => {
      const handler = jest.fn().mockResolvedValue('success');
      const schema = {
        description: 'Test tool',
        parameters: {
          type: 'object',
          properties: {
            param1: { type: 'string' }
          }
        }
      };

      registry.registerTool('test_tool', schema, handler);

      const result = await registry.executeTool('test_tool', { param1: null });

      expect(result.success).toBe(true);
    });
  });

  describe('getToolByName', () => {
    it('should return tool object for registered tool', () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool',
        parameters: { type: 'object' }
      };

      registry.registerTool('test_tool', schema, handler);

      const tool = registry.getToolByName('test_tool');

      expect(tool).toBeDefined();
      expect(tool.schema.name).toBe('test_tool');
      expect(tool.handler).toBe(handler);
    });

    it('should return null for non-existent tool', () => {
      const tool = registry.getToolByName('non_existent');
      expect(tool).toBeNull();
    });
  });

  describe('getToolNames', () => {
    it('should return empty array when no tools registered', () => {
      const names = registry.getToolNames();
      expect(names).toEqual([]);
    });

    it('should return array of tool names', () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool',
        parameters: { type: 'object' }
      };

      registry.registerTool('tool1', schema, handler);
      registry.registerTool('tool2', schema, handler);
      registry.registerTool('tool3', schema, handler);

      const names = registry.getToolNames();

      expect(names).toHaveLength(3);
      expect(names).toContain('tool1');
      expect(names).toContain('tool2');
      expect(names).toContain('tool3');
    });
  });

  describe('hasTool', () => {
    it('should return true for registered tool', () => {
      const handler = jest.fn();
      const schema = {
        description: 'Test tool',
        parameters: { type: 'object' }
      };

      registry.registerTool('test_tool', schema, handler);

      expect(registry.hasTool('test_tool')).toBe(true);
    });

    it('should return false for non-existent tool', () => {
      expect(registry.hasTool('non_existent')).toBe(false);
    });
  });
});
